declare(strict_types=1);require __DIR__.'/bootstrap.php';$root=dirname(__DIR__,2);$view=file_get_contents($root.'/app/Views/control-escaneres/dashboard.php');$kpi=file_get_contents($root.'/app/Views/components/dashboard-kpi.php');$css=file_get_contents($root.'/public/assets/css/control-escaneres/dashboard.css');$js=file_get_contents($root.'/public/assets/js/control-escaneres/dashboard.js');
test('vista usa ViewModel',fn()=>ok(str_contains($view,'$dashboardViewModel')&&!preg_match('/\bPDO\b|FROM scanners/i',$view)));test('selector GET con allowlist visual',fn()=>ok(str_contains($view,'method="get"')&&str_contains($view,'value="today"')&&str_contains($view,'value="7d"')&&str_contains($view,'value="30d"')));test('KPIs desde colección',fn()=>ok(str_contains($view,'$vm->kpis')&&str_contains($view,'dashboard-kpi.php')));test('alerta vacía honesta',fn()=>ok(str_contains($view,'No hay situaciones críticas')));test('tendencia tiene tabla accesible',fn()=>ok(str_contains($view,'<table')&&str_contains($view,'<thead>')&&str_contains($view,'<tbody>')));test('sin datos mock',fn()=>ok(!preg_match('/ESC-\d{3}|\b48\b|\b96%\b/',$view)));test('sin secretos',fn()=>ok(!preg_match('/\b(PIN|PUK|IMEI|ICCID|fingerprint|payload|stack trace)\b/i',$view)));test('enlaces descriptivos',fn()=>ok(str_contains($view,'Abrir expediente')&&str_contains($kpi,'Ver detalle de')));test('responsive móvil',fn()=>ok(str_contains($css,'max-width:767px')&&str_contains($css,'grid-template-columns:1fr')));test('sin scroll global forzado',fn()=>ok(!str_contains($css,'overflow-x:hidden')));test('JS no calcula ni consulta',fn()=>ok(!preg_match('/\b(fetch|XMLHttpRequest|setInterval|WebSocket)\b/',$js)));test('esencial disponible sin JS',fn()=>ok(str_contains($view,'method="get"')&&str_contains($view,'type="submit"')&&!str_contains($view,'document.write')));finish('Dashboard UX');
